// --- CONFIGURATION ---
const CLOUD_NAME = 'dlygycwmf'; 
const FONT = 'Verdana'; 
const FONT_SIZE = 48;   
const TEXT_COLOR = 'ffffff';

// --- BOX SETTINGS ---
const BOX_COLOR = '101010';     
const BOX_OPACITY = 85;         
const BOX_WIDTH = 900;
const BOX_HEIGHT = 210;         
const BOX_Y_FROM_BOTTOM = 140;
const CORNER_RADIUS = 30;       
const BORDER_WIDTH = 2;
const BORDER_COLOR = 'ffffff60'; 

// --- HELPER: Safe Text Encoding ---
function encodeCloudinaryText(str) {
  if (!str) return '';
  let s = String(str).trim();
  const lines = s.split(/\r\n|\r|\n/);

  // Encode each line
  const encodedLines = lines.map(line => {
    let encoded = encodeURIComponent(line);
    // Double-encode commas and slashes so Cloudinary treats them as text
    encoded = encoded.replace(/%2C/g, '%252C');
    encoded = encoded.replace(/%2F/g, '%252F');
    return encoded;
  });

  let clean = encodedLines.join('%0A');
  return clean;
}

return items.map((item, index) => {
  try {
    const publicId = item.json.public_id;
    if (!publicId) throw new Error(`Item ${index}: Missing public_id`);

    const imgHeight = parseInt(item.json.height) || 1024;
    const rawText = item.json.overlay_text || 'Breaking AI News';
    const encodedText = encodeCloudinaryText(rawText);

    // --- CALCULATE POSITIONING ---
    const boxCenterFromBottom = BOX_Y_FROM_BOTTOM + (BOX_HEIGHT / 2);
    const targetPixelY = imgHeight - boxCenterFromBottom;
    const imageCenterY = imgHeight / 2;
    const yOffsetForCenter = Math.round(targetPixelY - imageCenterY);

    // --- CREATE TEXT WITH BACKGROUND BOX ---
    // Cloudinary text overlay with background - verified syntax
    const textWithBoxLayer = [
      // Text layer definition
      `l_text:${FONT}_${FONT_SIZE}_bold_center:${encodedText}`,
      // Styling parameters
      `co_rgb:${TEXT_COLOR}`,
      `b_rgb:${BOX_COLOR}`,
      `o_${BOX_OPACITY}`,
      `w_${BOX_WIDTH - 60}`,
      `c_fit`,
      `bo_${BORDER_WIDTH}px_solid_rgb:${BORDER_COLOR}`,
      `r_${CORNER_RADIUS}`,
      // Layer application and positioning
      `fl_layer_apply`,
      `g_center`,
      `y_${yOffsetForCenter}`
    ].join(',');

    // --- ASSEMBLE URL ---
    const baseUrl = `https://res.cloudinary.com/${CLOUD_NAME}/image/upload`;
    const finalUrl = `${baseUrl}/${textWithBoxLayer}/${publicId}.png`;

    return {
      json: {
        ...item.json,
        generated_instagram_url: finalUrl
      }
    };

  } catch (error) {
    return {
      json: {
        ...item.json,
        error: true,
        error_message: error.message,
        generated_instagram_url: null 
      }
    };
  }
});
